94: func newInstanceSettings(httpClientProvider *httpclient.Provider) datasource.InstanceFactoryFunc {
95: 	return func(ctx context.Context, settings backend.DataSourceInstanceSettings) (instancemgmt.Instance, error) {
96: 		opts, err := settings.HTTPClientOptions(ctx)
97: 		if err != nil {
98: 			return nil, backend.DownstreamError(fmt.Errorf("error reading settings: %w", err))
99: 		}
100: 		opts.ForwardHTTPHeaders = true
101: 
102: 		client, err := httpClientProvider.New(opts)
103: 		if err != nil {
104: 			return nil, backend.DownstreamError(fmt.Errorf("error creating http client: %w", err))
105: 		}
106: 
107: 		model := &datasourceInfo{
108: 			HTTPClient: client,
109: 			URL:        settings.URL,
110: 			streams:    make(map[string]data.FrameJSONCache),
111: 		}
112: 		return model, nil
113: 	}
