182: func (s *Service) QueryData(ctx context.Context, req *backend.QueryDataRequest) (*backend.QueryDataResponse, error) {
183: 	dsInfo, err := s.getDSInfo(ctx, req.PluginContext)
184: 	_, fromAlert := req.Headers[fromAlertHeaderName]
185: 	logger := s.logger.FromContext(ctx).With("fromAlert", fromAlert)
186: 	if err != nil {
187: 		logger.Debug("Failed to get data source info", "err", err)
188: 		return nil, err
189: 	}
190: 
191: 	responseOpts := ResponseOpts{
192: 		logsDataplane: isFeatureEnabled(ctx, flagLokiLogsDataplane),
193: 	}
194: 
195: 	return queryData(ctx, req, dsInfo, responseOpts, s.tracer, logger, isFeatureEnabled(ctx, flagLokiRunQueriesInParallel), isFeatureEnabled(ctx, flagLogQLScope))
196: }
