27: var (
28: 	errEndBeforeStart     = errors.New("end timestamp must not be before or equal to start time")
29: 	errZeroOrNegativeStep = errors.New("zero or negative query resolution step widths are not accepted. Try a positive integer")
30: 	errNegativeStep       = errors.New("negative query resolution step widths are not accepted. Try a positive integer")
31: 	errStepTooSmall       = errors.New("exceeded maximum resolution of 11,000 points per time series. Try increasing the value of the step parameter")
32: 	errNegativeInterval   = errors.New("interval must be >= 0")
