35: // QueryStatus holds the status of a query
36: type QueryStatus string
37: 
38: // QueryStatus values
39: const (
40: 	QueryStatusSuccess = "success"
41: 	QueryStatusFail    = "fail"
42: 	// How much stack space to allocate for unescaping JSON strings; if a string longer
43: 	// than this needs to be escaped, it will result in a heap allocation
44: 	unescapeStackBufSize = 64
45: )
46: 
47: // QueryResponse represents the http json response to a Loki range and instant query
48: type QueryResponse struct {
49: 	Status   string            `json:"status"`
50: 	Warnings []string          `json:"warnings,omitempty"`
51: 	Data     QueryResponseData `json:"data"`
52: }
53: 
54: func (q *QueryResponse) UnmarshalJSON(data []byte) error {
55: 	return jsonparser.ObjectEach(data, func(key, value []byte, dataType jsonparser.ValueType, offset int) error {
56: 		switch string(key) {
57: 		case "status":
58: 			q.Status = string(value)
59: 		case "warnings":
60: 			var warnings []string
61: 			if _, err := jsonparser.ArrayEach(value, func(value []byte, dataType jsonparser.ValueType, offset int, err error) {
62: 				if dataType == jsonparser.String {
63: 					warnings = append(warnings, unescapeJSONString(value))
64: 				}
65: 			}); err != nil {
66: 				return err
67: 			}
68: 
69: 			q.Warnings = warnings
70: 		case "data":
71: 			var responseData QueryResponseData
72: 			if err := responseData.UnmarshalJSON(value); err != nil {
73: 				return err
74: 			}
75: 			q.Data = responseData
76: 		}
77: 		return nil
78: 	})
79: }
80: 
81: func unescapeJSONString(b []byte) string {
82: 	var stackbuf [unescapeStackBufSize]byte // stack-allocated array for allocation-free unescaping of small strings
83: 	bU, err := jsonparser.Unescape(b, stackbuf[:])
84: 	if err != nil {
85: 		return ""
86: 	}
87: 
88: 	return string(bU)
89: }
