91: // PushRequest models a log stream push but is unmarshalled to proto push format.
92: type PushRequest struct {
93: 	Streams []LogProtoStream `json:"streams"`
94: }
95: 
96: // LogProtoStream helps with unmarshalling of each log stream for push request.
97: // This might look un-necessary but without it the CPU usage in benchmarks was increasing by ~25% :shrug:
98: type LogProtoStream logproto.Stream
99: 
100: func (s *LogProtoStream) UnmarshalJSON(data []byte) error {
101: 	err := jsonparser.ObjectEach(data, func(key, val []byte, ty jsonparser.ValueType, _ int) error {
102: 		switch string(key) {
103: 		case "stream":
104: 			var labels LabelSet
105: 			if err := labels.UnmarshalJSON(val); err != nil {
106: 				return err
107: 			}
108: 			s.Labels = labels.String()
109: 		case "values":
110: 			if ty == jsonparser.Null {
111: 				return nil
112: 			}
113: 			entries, err := unmarshalHTTPToLogProtoEntries(val)
114: 			if err != nil {
115: 				return err
116: 			}
117: 			s.Entries = entries
118: 		}
119: 		return nil
120: 	})
121: 	return err
122: }
