124: func unmarshalHTTPToLogProtoEntries(data []byte) ([]logproto.Entry, error) {
125: 	var (
126: 		entries    []logproto.Entry
127: 		parseError error
128: 	)
129: 	if _, err := jsonparser.ArrayEach(data, func(value []byte, ty jsonparser.ValueType, _ int, err error) {
130: 		if err != nil || parseError != nil {
131: 			return
132: 		}
133: 		if ty == jsonparser.Null {
134: 			return
135: 		}
136: 		e, err := unmarshalHTTPToLogProtoEntry(value)
137: 		if err != nil {
138: 			parseError = err
139: 			return
140: 		}
141: 		entries = append(entries, e)
142: 	}); err != nil {
143: 		parseError = err
144: 	}
145: 
146: 	if parseError != nil {
147: 		return nil, parseError
148: 	}
149: 
150: 	return entries, nil
151: }
152: 
153: func unmarshalHTTPToLogProtoEntry(data []byte) (logproto.Entry, error) {
154: 	var (
155: 		i          int
156: 		parseError error
157: 		e          logproto.Entry
158: 	)
159: 	_, err := jsonparser.ArrayEach(data, func(value []byte, t jsonparser.ValueType, _ int, _ error) {
160: 		// assert that both items in array are of type string
161: 		if (i == 0 || i == 1) && t != jsonparser.String {
162: 			parseError = jsonparser.MalformedStringError
163: 			return
164: 		} else if i == 2 && t != jsonparser.Object {
165: 			parseError = jsonparser.MalformedObjectError
166: 			return
167: 		}
168: 		switch i {
169: 		case 0: // timestamp
170: 			ts, err := jsonparser.ParseInt(value)
171: 			if err != nil {
172: 				parseError = err
173: 				return
174: 			}
175: 			e.Timestamp = time.Unix(0, ts)
176: 		case 1: // value
177: 			v, err := jsonparser.ParseString(value)
178: 			if err != nil {
179: 				parseError = err
180: 				return
181: 			}
182: 			e.Line = v
183: 		case 2: // structuredMetadata
184: 			var structuredMetadata []logproto.LabelAdapter
185: 			err := jsonparser.ObjectEach(value, func(key, val []byte, dataType jsonparser.ValueType, _ int) error {
186: 				if dataType != jsonparser.String {
187: 					return jsonparser.MalformedStringError
188: 				}
189: 				structuredMetadata = append(structuredMetadata, logproto.LabelAdapter{
190: 					Name:  string(key),
191: 					Value: string(val),
192: 				})
193: 				return nil
194: 			})
195: 			if err != nil {
196: 				parseError = err
197: 				return
198: 			}
199: 			e.StructuredMetadata = structuredMetadata
200: 		}
201: 		i++
202: 	})
203: 	if parseError != nil {
204: 		return e, parseError
205: 	}
206: 	return e, err
207: }
