209: // ResultType holds the type of the result
210: type ResultType string
211: 
212: // ResultType values
213: const (
214: 	ResultTypeStream = "streams"
215: 	ResultTypeScalar = "scalar"
216: 	ResultTypeVector = "vector"
217: 	ResultTypeMatrix = "matrix"
218: )
