220: // ResultValue interface mimics the promql.Value interface
221: type ResultValue interface {
222: 	Type() ResultType
223: }
224: 
225: // QueryResponseData represents the http json response to a label query
226: type QueryResponseData struct {
227: 	ResultType ResultType   `json:"resultType"`
228: 	Result     ResultValue  `json:"result"`
229: 	Statistics stats.Result `json:"stats"`
230: }
231: 
232: // Type implements the promql.Value interface
233: func (Streams) Type() ResultType { return ResultTypeStream }
234: 
235: // Type implements the promql.Value interface
236: func (Scalar) Type() ResultType { return ResultTypeScalar }
237: 
238: // Type implements the promql.Value interface
239: func (Vector) Type() ResultType { return ResultTypeVector }
240: 
241: // Type implements the promql.Value interface
242: func (Matrix) Type() ResultType { return ResultTypeMatrix }
