244: // Streams is a slice of Stream
245: type Streams []Stream
246: 
247: func (ss *Streams) UnmarshalJSON(data []byte) error {
248: 	var parseError error
249: 	_, err := jsonparser.ArrayEach(data, func(value []byte, dataType jsonparser.ValueType, offset int, err error) {
250: 		var stream Stream
251: 		if err := stream.UnmarshalJSON(value); err != nil {
252: 			parseError = err
253: 			return
254: 		}
255: 		*ss = append(*ss, stream)
256: 	})
257: 	if parseError != nil {
258: 		return parseError
259: 	}
260: 	return err
261: }
262: 
263: func (s Streams) ToProto() []logproto.Stream {
264: 	if len(s) == 0 {
265: 		return nil
266: 	}
267: 	result := make([]logproto.Stream, 0, len(s))
268: 	for _, s := range s {
269: 		entries := *(*[]logproto.Entry)(unsafe.Pointer(&s.Entries))
270: 		result = append(result, logproto.Stream{
271: 			Labels:  s.Labels.String(),
272: 			Entries: entries,
273: 		})
274: 	}
275: 	return result
