457: func ParseRangeQuery(r *http.Request) (*RangeQuery, error) {
458: 	var result RangeQuery
459: 	var err error
460: 
461: 	result.Query = query(r)
462: 	result.Start, result.End, err = bounds(r)
463: 	if err != nil {
464: 		return nil, err
465: 	}
466: 
467: 	if result.End.Before(result.Start) {
468: 		return nil, errEndBeforeStart
469: 	}
470: 
471: 	result.Limit, err = limit(r)
472: 	if err != nil {
473: 		return nil, err
474: 	}
475: 
476: 	result.Direction, err = direction(r)
477: 	if err != nil {
478: 		return nil, err
479: 	}
480: 
481: 	result.Step, err = step(r, result.Start, result.End)
482: 	if err != nil {
483: 		return nil, err
484: 	}
485: 
486: 	if result.Step <= 0 {
487: 		return nil, errZeroOrNegativeStep
488: 	}
489: 
490: 	result.Shards = shards(r)
491: 
492: 	// For safety, limit the number of returned points per timeseries.
493: 	// This is sufficient for 60s resolution for a week or 1h resolution for a year.
494: 	if (result.End.Sub(result.Start) / result.Step) > 11000 {
495: 		return nil, errStepTooSmall
496: 	}
497: 
498: 	result.Interval, err = interval(r)
499: 	if err != nil {
500: 		return nil, err
501: 	}
502: 
503: 	if result.Interval < 0 {
504: 		return nil, errNegativeInterval
505: 	}
506: 
507: 	if GetVersion(r.URL.Path) == VersionLegacy {
508: 		result.Query, err = parseRegexQuery(r)
509: 		if err != nil {
510: 			return nil, httpgrpc.Errorf(http.StatusBadRequest, "%s", err.Error())
511: 		}
